mapper.insert:
INSERT INTO CMS_SITE (
    SITE_CD
  , SITE_NM
  , SITE_URL
  , SITE_DESC
  , USE_YN
  , 
) VALUES (
    #{siteCd}
  , #{siteNm}
  , #{siteUrl}
  , #{siteDesc}
  , #{useYn}
  , 
)

mapper.update:
UPDATE CMS_SITE
   SET SITE_NM   = #{vo.siteNm}
     , SITE_URL  = #{vo.siteUrl}
     , SITE_DESC = #{vo.siteDesc}
     , USE_YN    = #{vo.useYn}
     , 
 WHERE SITE_CD   = #{siteCd}

mapper.insert:
INSERT INTO CMS_SITE_ACC_PERM (
    SITE_CD
  , SN
  , USE_YN
  , SITE_PERM_KND_SE
  , SITE_PERM_NM
  , SITE_PERM_DESC
  , USE_ST_YMD
  , USE_END_YMD
  , 
) VALUES (
    #{siteCd}
  , (SELECT NVL(MAX(SN), 0) + 1 FROM CMS_SITE_ACC_PERM WHERE SITE_CD = #{siteCd})
  , #{useYn}
  , #{sitePermKndSe}
  , #{sitePermNm}
  , #{sitePermDesc}
  , #{useStYmd}
  , #{useEndYmd}
  , 
)

mapper.update:
UPDATE CMS_SITE_ACC_PERM
   SET USE_YN           = #{vo.useYn}
     , SITE_PERM_KND_SE = #{vo.sitePermKndSe}
     , SITE_PERM_NM     = #{vo.sitePermNm}
     , SITE_PERM_DESC   = #{vo.sitePermDesc}
     , USE_ST_YMD       = #{vo.useStYmd}
     , USE_END_YMD      = #{vo.useEndYmd}
     , 
 WHERE SITE_CD          = #{siteCd}
   AND SN               = #{sn}
